from flask import Flask, request, jsonify

app = Flask(__name__)
mfa_enabled_users = {}

@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    data = request.get_json()
    user_email = data.get('email')
    mfa_enabled_users[user_email] = True
    return jsonify({'message': 'MFA enabled for {}'.format(user_email)})

@app.route('/disable-mfa', methods=['POST'])
def disable_mfa():
    data = request.get_json()
    user_email = data.get('email')
    if user_email in mfa_enabled_users:
        del mfa_enabled_users[user_email]
        return jsonify({'message': 'MFA disabled for {}'.format(user_email)})
    return jsonify({'error': 'MFA not enabled for {}'.format(user_email)})

@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    data = request.get_json()
    user_email = data.get('email')
    if user_email in mfa_enabled_users:
        # Add logic here to send reset link to user's email
        mfa_enabled_users[user_email] = False
        return jsonify({'message': 'Reset link sent to {}'.format(user_email)})
    return jsonify({'error': 'MFA not enabled for {}'.format(user_email)})

if __name__ == '__main__':
    app.run()